window.__QUIZ_DATA__=[{"id":"theory>Biology>2025>1>a","subject":"Biology","year":"2025","type":"Theory","sub_label":"a","group":"","topic":"CONCEPT OF LIVING : EXCRETORY SYSTEMS","question":"Explain briefly the term excretion","images":[],"marking_scheme":"Excretion Is the process by which living organisms;remove/eliminate waste products/toxic substances/carbon (IV) oxide/urea/excess salts;  - produced from metabolism/chemical reactions in the body; to maintain homeostasis/internal balance.","marks":"3","difficulty":"2"},{"id":"theory>Biology>2025>1>b>i","subject":"Biology","year":"2025","type":"Theory","sub_label":"i","group":"","topic":"CONCEPT OF LIVING : EXCRETORY SYSTEMS","question":"Name two excretory products each of mammals","images":[],"marking_scheme":"-Salts;  - Carbon(IV)oxide;  -Bile pigments.  - Urea/uric acid/ammonia;  - Water;","marks":"2","difficulty":"1"},{"id":"theory>Biology>2025>1>b>ii","subject":"Biology","year":"2025","type":"Theory","sub_label":"ii","group":"","topic":"CONCEPT OF LIVING : EXCRETORY SYSTEMS","question":"Name two excretory products each of plants","images":[],"marking_scheme":"-Alkaloids;-  -Oxygen;Resins;  - Carbon(IV) oxide;\t  - Water/water vapour;\t  -Gums/latex/sap.  - Tannins;","marks":"2","difficulty":"1"},{"id":"theory>Biology>2025>1>c","subject":"Biology","year":"2025","type":"Theory","sub_label":"c","group":"","topic":"CONCEPT OF LIVING : EXCRETORY SYSTEMS","question":"Complete the table below.OrganismExcretory structureMechanism involved in excretionAdaptation of the structure for excretionParameciumThin semi permeable membranePlanariaLeaf of plantTranspirationEarthworm","images":[],"marking_scheme":"OrganismExcretory structureMechanism involved in excretionAdaptation of the structure for excretionParameciumContractile vacuoleOsmosis/diffusionThin semi permeable membranePlanariaFlame cell/photonephridiumUltrafiltration/protonephridia  systemPresence of  cilia/thin/permeable cell membraneLeaf of plantStomatal pore/stomataTranspirationPresence of guard cells  EarthwormNephridium/NephridiaTubular secretion/ultrafiltration/selective reabsorptionCoiled/ciliated excretory tubules/richly suppliedwith blood vessels","marks":"10","difficulty":"2"},{"id":"theory>Biology>2025>1>d","subject":"Biology","year":"2025","type":"Theory","sub_label":"d","group":"","topic":"CONCEPT OF LIVING : EXCRETORY SYSTEMS","question":"State three functions of the kidney in humans","images":[],"marking_scheme":"-Osmoregulation  -Salt/ion balance  -Regulation of blood pH  -Regulation of blood pressure;  -Production of hormones  -Selective reabsorption","marks":"3","difficulty":"2"},{"id":"theory>Biology>2025>2>a","subject":"Biology","year":"2025","type":"Theory","sub_label":"a","group":"","topic":"PLANT AND ANIMAL NUTRITION : MODES OF NUTRITION","question":"State two differences between photosynthetic mode of nutrition and chemosynthetic mode of nutritionPhotosynthetic nutritionChemosynthetic nutrition","images":[],"marking_scheme":"Photosynthetic nutritionChemosynthetic nutritionEnergy is obtained from light/sunenergy is obtained from chemicals/inorganic substanceschlorophyll is requiredchlorophyll is not requiredRaw materials are carbon (IV) oxide and waterraw materials are carbon (IV) oxide and inorganic compounds/ammoniaInvolves trapping of light/sunlightinvolves the oxidation of inorganic substancesOxygen/O2 is released/given off as by-productoxygen/O2 is not released/given off as by-productCarried out by (green)plants/cyanobacteria/green algaecarried out by chemosynthetic bacteria/archaea","marks":"2","difficulty":"2"},{"id":"theory>Biology>2025>2>b>i","subject":"Biology","year":"2025","type":"Theory","sub_label":"i","group":"","topic":"BASIC ECOLOGICAL CONCEPTS : MICROORGANISMS: MAN AND HIS HEALTH.","question":"What are saprophytes?","images":[],"marking_scheme":"Saprophytes are organisms; that obtain their nutrients from dead and decaying organic matter;  through external digestion.","marks":"2","difficulty":"1"},{"id":"theory>Biology>2025>2>b>ii","subject":"Biology","year":"2025","type":"Theory","sub_label":"ii","group":"","topic":"MICROORGANISMS: MAN AND HEALTH : MICROORGANISMS IN ACTION","question":"Give two examples of saprophytic organisms","images":[],"marking_scheme":"-Rhizopus/bread mould/mold;\t  -Mushroom;  - Yeast;\t  -Mycorrhiza;  - Mucor;  -Toadstool;  - (Some) Bacteria/Pseudomonas/\t  -Bacillus subtili:/Clostridium;\t  -Indian pipe.  - Corallorhiza orchids;","marks":"2","difficulty":"1"},{"id":"theory>Biology>2025>2>b>iii","subject":"Biology","year":"2025","type":"Theory","sub_label":"iii","group":"","topic":"PLANT AND ANIMAL NUTRITION : MODES OF NUTRITION","question":"Explain briefly the mode of feeding in saprophytes","images":[],"marking_scheme":"-They feed on dead organic matter;  -they secrete digestive enzymes on the substrate/food material/dead material;  -this causes the breakdown/digestion of food into simple/soluble substances  -the digestion is extracellular/outside the body  -the soluble end product is absorbed/assimlated into the body through the cell membrane.","marks":"4","difficulty":"2"},{"id":"theory>Biology>2025>2>b>iv","subject":"Biology","year":"2025","type":"Theory","sub_label":"iv","group":"","topic":"MICROORGANISMS: MAN AND HEALTH : MICROORGANISMS IN ACTION","question":"State three ways by which saprophytes are of economic importance","images":[],"marking_scheme":"-They cause decay of organic matter to increase soil manure/fertility/nutrients;  --They reduce the level of refuse/waste in the enviroment;  -Some saprophytes/mushrooms are edible  -They cause spoilage of food;  -They are used in industries for fermentation;  -Parasitic saprophytes cause diseases in humans/animals/plants;  -They are used to produce enzymes/antibiotics/other valuable substances/in biotechnology.","marks":"3","difficulty":"2"},{"id":"theory>Biology>2025>2>c","subject":"Biology","year":"2025","type":"Theory","sub_label":"c","group":"","topic":"PLANT AND ANIMAL NUTRITION : FEEDING HABITS","question":"State three characteristic features of carnivorous plants","images":[],"marking_scheme":"They:  -have attractive mechanisms/bright colour to lure preys  -have special devices/structures for trapping and digesting insects/small animals  -usually grow in areas/habitats deficient in nitrogen  -obtain nitrogen supplements from insects/small animals  -Secrete enzymes/rely on symbiotic bacteria to break down their prey","marks":"3","difficulty":"1"},{"id":"theory>Biology>2025>2>d>i","subject":"Biology","year":"2025","type":"Theory","sub_label":"i","group":"","topic":"PLANT AND ANIMAL NUTRITION : FEEDING HABITS","question":"State the feeding habit of butterfly","images":[],"marking_scheme":"Fluid feeding/sucking","marks":"1","difficulty":"1"},{"id":"theory>Biology>2025>2>d>ii","subject":"Biology","year":"2025","type":"Theory","sub_label":"ii","group":"","topic":"PLANT AND ANIMAL NUTRITION : FEEDING HABITS","question":"State the feeding habit of mosquito larva","images":[],"marking_scheme":"Filter feeding","marks":"1","difficulty":"1"},{"id":"theory>Biology>2025>2>d>iii","subject":"Biology","year":"2025","type":"Theory","sub_label":"iii","group":"","topic":"PLANT AND ANIMAL NUTRITION : FEEDING HABITS","question":"State the feeding habit of mucor","images":[],"marking_scheme":"Saprophytic","marks":"1","difficulty":"1"},{"id":"theory>Biology>2025>2>d>iv","subject":"Biology","year":"2025","type":"Theory","sub_label":"iv","group":"","topic":"PLANT AND ANIMAL NUTRITION : FEEDING HABITS","question":"State the feeding habit of housefly","images":[],"marking_scheme":"Fluid feeding/sponging","marks":"1","difficulty":"1"},{"id":"theory>Biology>2025>3>a","subject":"Biology","year":"2025","type":"Theory","sub_label":"a","group":"","topic":"BASIC ECOLOGICAL CONCEPTS : NUTRIENT CYCLING IN NATURE","question":"Explain briefly how how carbon(IV)oxide and oxygen are balanced in nature","images":[],"marking_scheme":"-during the process of photosynthesis;  plants take up carbon (IV) oxide in the atmosphere;  to release oxygen;  animals take up the released oxygen during respiration;to release carbon (IV) oxide","marks":"2","difficulty":"2"},{"id":"theory>Biology>2025>3>b","subject":"Biology","year":"2025","type":"Theory","sub_label":"b","group":"","topic":"BASIC ECOLOGICAL CONCEPTS : HABITATS","question":"List five factors that affect the distribution of plants in their habitats","images":[],"marking_scheme":"Temperature;\t  -Humidity;  -Edaphic/soil;\t  -Wind;  -Rainfall;\t  -pH;  -Light/sunlight;\t  -Topography.  -Anthropogenic/human/man","marks":"5","difficulty":"2"},{"id":"theory>Biology>2025>3>c>i","subject":"Biology","year":"2025","type":"Theory","sub_label":"i","group":"","topic":"BASIC ECOLOGICAL CONCEPTS : POPULATION STUDIES BY SAMPLING","question":"What is overcrowding in an ecosystem?","images":[],"marking_scheme":"Overcrowding in an ecosystem This is when the population;  of organism in a habitat;increases beyond a point/carrying capacity; where the resources in the habitat are not enough/are limited; to support all the individuals in the population","marks":"2","difficulty":"2"},{"id":"theory>Biology>2025>3>c>ii","subject":"Biology","year":"2025","type":"Theory","sub_label":"ii","group":"","topic":"BASIC ECOLOGICAL CONCEPTS : POPULATION STUDIES BY SAMPLING","question":"List five effects of overcrowding in an ecosystem","images":[],"marking_scheme":"It leads to:decrease in reproduction/natality/fecundity;  food shortage/competition for food;shortage of other resources/water/soil nutrients/light etc;  restricted living space for breeding;outbreak of diseases/morbidity;  predation;build-up of toxic wastes in the environment/pollution;  emigration;  cannibalism;  increase in competition for resources;  high mortality rate","marks":"1","difficulty":"2"},{"id":"theory>Biology>2025>3>d>i","subject":"Biology","year":"2025","type":"Theory","sub_label":"i","group":"","topic":"BASIC ECOLOGICAL CONCEPTS : ECOLOGICAL FACTORS","question":"Distinguish between density-dependent factors and density-independent factors in an ecosystem","images":[],"marking_scheme":"Density-dependent factors are factors that affect population in intensity as population density changes;its effects are determined by the size of the population; while density-independent factors affect the growth of the population irrespective of its size.","marks":"2","difficulty":"3"},{"id":"theory>Biology>2025>3>d>ii","subject":"Biology","year":"2025","type":"Theory","sub_label":"ii","group":"","topic":"BASIC ECOLOGICAL CONCEPTS : POPULATION STUDIES BY SAMPLING","question":"Give two examples of density-dependent factors","images":[],"marking_scheme":"Competition;  Diseases;  Parasitism;  Waste accumulation/pollution;  Migration;  Predation.","marks":"2","difficulty":"2"},{"id":"theory>Biology>2025>3>d>iii","subject":"Biology","year":"2025","type":"Theory","sub_label":"iii","group":"","topic":"BASIC ECOLOGICAL CONCEPTS : ECOSYSTEM","question":"Explain briefly how density-dependent factors and density-independent factors affect the dynamic equilibrium in an ecosystem","images":[],"marking_scheme":"Density-dependent factors and density-indepenc'ent factors ma niain dynamic equilibrium by increasing; or decreasing the factors that change the population size (e.g. death rate, birth rate,migration); of each population in the community.","marks":"2","difficulty":"3"},{"id":"theory>Biology>2025>4>a>i","subject":"Biology","year":"2025","type":"Theory","sub_label":"i","group":"","topic":"BIOLOGY OF HEREDITY (GENETICS) : TRANSMISSION AND EXPRESSION OF CHARACTERISTICS IN ORGANISMS","question":"A tall man and a tall woman have a child that is short.    State two factors that could be responsible for the height of their child","images":[],"marking_scheme":"Malnutrition/inadequate feeding/Environmental factor;  Chronic malabsorption of nutrient:  Genetic factor/mutation;  Recessive gene for shortness;  Polygenic inheritance;  Deficiency of growth hormone;  Chronic illness;\t  Bone/skeletal malformation.","marks":"2","difficulty":"2"},{"id":"theory>Biology>2025>4>a>ii","subject":"Biology","year":"2025","type":"Theory","sub_label":"ii","group":"","topic":"BIOLOGY OF HEREDITY (GENETICS) : GENETIC TERMINOLOGIES","question":"With the aid of a genetic diagram, give the genotype of their offspring if the allele for tallness is T.","images":["data:image/png;base64,"],"marking_scheme":"","marks":"8","difficulty":"3"},{"id":"theory>Biology>2025>4>a>iii","subject":"Biology","year":"2025","type":"Theory","sub_label":"iii","group":"","topic":"BIOLOGY OF HEREDITY (GENETICS) : TRANSMISSION AND EXPRESSION OF CHARACTERISTICS IN ORGANISMS","question":"Give the genotype of the child that is short","images":[],"marking_scheme":"tt","marks":"1","difficulty":"2"},{"id":"theory>Biology>2025>4>b>i","subject":"Biology","year":"2025","type":"Theory","sub_label":"i","group":"","topic":"BIOLOGY OF HEREDITY (GENETICS) : GENETIC TERMINOLOGIES","question":"Define the term genotype","images":[],"marking_scheme":"This is the genetic makeup of an organism; which is the combination of alleles that an individual inherits from their parents.","marks":"2","difficulty":"1"},{"id":"theory>Biology>2025>4>b>ii","subject":"Biology","year":"2025","type":"Theory","sub_label":"ii","group":"","topic":"VARIATION IN POPULATION : MORPHOLOGICAL VARIATIONS","question":"List two factors that could cause variation in a character within the same species","images":[],"marking_scheme":"Genetic factor/mutation/crossing over/inherited genes;  - Nutrition;  Climate/weather/environment;  Diseases/infections;  Lifestyle/habits.","marks":"2","difficulty":"2"},{"id":"theory>Biology>2025>4>c>i","subject":"Biology","year":"2025","type":"Theory","sub_label":"i","group":"","topic":"BIOLOGY OF HEREDITY (GENETICS) : GENETIC TERMINOLOGIES","question":"Define the term allele","images":[],"marking_scheme":"Alleles are a pair of contrasting/alternative forms of the same gene; occupying the same position/locus on a pair of homologous chromosomes; inherited from each parent.","marks":"3","difficulty":"1"},{"id":"theory>Biology>2025>4>c>ii","subject":"Biology","year":"2025","type":"Theory","sub_label":"ii","group":"","topic":"BIOLOGY OF HEREDITY (GENETICS) : GENETIC TERMINOLOGIES","question":"State two differences between genotype and phenotype  GenotypePhenotype","images":[],"marking_scheme":"Genotype,Phenotype  The genetic makeup of an  organism/the alleles an organism carries,the observable/physical appearance an organism  Inherited from parents,result of genotype and environmental influences  Represented by allele combinations/AA;Aa;aa,includes traits like height, eye colour,  blood type,etc  Not directly visible,can be seen or measured  Not directly affected by the  environment,can be influenced by environmental factors/nutrition/climate;  Remains constant throughout life,can change over time.","marks":"2","difficulty":"2"},{"id":"theory>Biology>2025>5>a","subject":"Biology","year":"2025","type":"Theory","sub_label":"a","group":"","topic":"ECOLOGICAL MANAGEMENT : ADAPTATION OF ORGANISMS TO HABITATS.","question":"State five effects of high temperature on organisms in their habitats","images":[],"marking_scheme":"Death;  Migration/species redistribution;Disrupted life cycle/growth pattern;  Reduced yield/reproduction;  Dehydration;  Enzyme denaturation;Altered metabolism/reduced metabolic rate;  Outbreak of diseases/epidemic;Increased/rate of transpiration/sweating;  Heat stress/overheating.","marks":"5","difficulty":"3"},{"id":"theory>Biology>2025>5>b","subject":"Biology","year":"2025","type":"Theory","sub_label":"b","group":"","topic":"BASIC ECOLOGICAL CONCEPTS : ECOSYSTEM","question":"Mention five effects of bush burning on the ecosystem","images":[],"marking_scheme":"Loss of biodiversity;  Disruption of food chains;Change in species composition/distribution;  Spread of pests and diseases;  Disrupted reproductive cycles;Soil degradation/desertification/soil erosion;  Climate change/altered weather patterns;  Emission of Greenhouse gases;  Flooding;  Drought  Air pollution","marks":"5","difficulty":"2"},{"id":"theory>Biology>2025>5>c","subject":"Biology","year":"2025","type":"Theory","sub_label":"c","group":"","topic":"BASIC ECOLOGICAL CONCEPTS : MICROORGANISMS: MAN AND HIS HEALTH.~~MICROORGANISMS: MAN AND HEALTH : PUBLIC HEALTH","question":"State four roles of the World Health Organization in the control of pandemic diseases","images":[],"marking_scheme":"Global surveillance/monitoring;  Vaccine development/distribution;Establishment of health protocols/standar is/guidelines;  Coordination of international response;Public enlightenment/creating awareness/lissemiration of useful information;  Mobilising resources/equipment/supplies;Establish equity and advocacy for vulnerable populations;  Keep records/statistics;Promotes health research/techical expert se/training of he alth workers;  Quarantine/inoculation.","marks":"4","difficulty":"2"},{"id":"theory>Biology>2025>5>d>i","subject":"Biology","year":"2025","type":"Theory","sub_label":"i","group":"","topic":"ADAPTATION FOR SURVIVAL AND EVOLUTION : BEHAVIOURAL ADAPTATIONS IN SOCIAL ANIMALS.","question":"Explain briefly countershading as an adaptive feature of Tilapia in freshwater habitats","images":[],"marking_scheme":"Tilapia has a darker colouration on its upper/dorsal side;which blends with the dark/murky bottom of the water when viewed from above; and a lighter colouration on its belly/ventral side;which blends with the bright surface/sky when viewed from below","marks":"3","difficulty":"2"},{"id":"theory>Biology>2025>5>d>ii","subject":"Biology","year":"2025","type":"Theory","sub_label":"ii","group":"","topic":"ADAPTATION FOR SURVIVAL AND EVOLUTION : BEHAVIOURAL ADAPTATIONS IN SOCIAL ANIMALS.","question":"Explain briefly seasonal migration in birds","images":[],"marking_scheme":"This is the regular long-distance movement of birds;between their breeding grounds and non-breeding areas; in response to changes in seasons.","marks":"2","difficulty":"2"},{"id":"theory>Biology>2025>5>e>i","subject":"Biology","year":"2025","type":"Theory","sub_label":"i","group":"","topic":"MICROORGANISMS: MAN AND HEALTH : MICROORGANISMS IN ACTION","question":"Name five groups of microorganisms","images":[],"marking_scheme":"-Viruses;  - Bacteria;  - Protozoa;  - Fungi;  - Algae.","marks":"5","difficulty":"1"},{"id":"theory>Biology>2025>5>e>ii","subject":"Biology","year":"2025","type":"Theory","sub_label":"ii","group":"","topic":"BASIC ECOLOGICAL CONCEPTS : MICROORGANISMS: MAN AND HIS HEALTH.","question":"Name two groups among the groups named in 5ei which have members that are pathogenic","images":[],"marking_scheme":"-Viruses;  - Bacteria;  - Protozoa;  - Fungi.","marks":"2","difficulty":"2"},{"id":"theory>Biology>2025>5>f>i","subject":"Biology","year":"2025","type":"Theory","sub_label":"i","group":"","topic":"VARIATION IN POPULATION : MORPHOLOGICAL VARIATIONS","question":"A patient with blood group O requires blood transfusion    Name two blood groups that the patient should not be transfused with","images":[],"marking_scheme":"- Blood group A;  - Blood group B;  - Blood group AB.","marks":"2","difficulty":"2"},{"id":"theory>Biology>2025>5>f>ii","subject":"Biology","year":"2025","type":"Theory","sub_label":"ii","group":"","topic":"BIOLOGY OF HEREDITY (GENETICS) : APPLICATION OF THE PRINCIPLES OF HEREDITY","question":"State two likely effects that the transfusion of any of the blood groups named in 5fi would have on the patient","images":[],"marking_scheme":"-Agglutination/clumping of blood;  Asphyxiation;  Severe pain;  Shock/coma;  - Death;  - Kidney failure;  - Destruction of red blood cells;  - Dark urine/haemoglobinuria;  -\tLow blood pressure/hypotension;  -\tFever.","marks":"2","difficulty":"2"}];